INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-00421', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲110年度有下列所得，其於辦理該年度綜合所得稅結算申報時，依所得基本稅額條例規定，何 者免計入基本所得額？', '["取得以父親為要保人於96年投保人壽保險之保險給付（非死亡給付）新臺幣100萬元", "出售我國證券投資信託事業私募證券投資信託基金的受益憑證，獲利新臺幣100萬元", "申報綜合所得稅時減除之非現金捐贈新臺幣100萬元", "出售美國公司發行股票，獲利新臺幣80萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00422', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', 'A早年喪偶，育有3名子女甲、乙、丙，甲有未滿18足歲的獨生女，乙已婚無子女，丙未婚，嗣 A再娶18歲妻，A於111年4月1日過世，甲、乙、丙均抛棄繼承，本件依遺產及贈與稅法規 定，配偶扣除額及繼承人扣除額共多少？', '["543萬元", "643萬元", "693萬元", "793萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00423', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，下列情形何者在申報營利事業所得稅時應認列為損益項目？', '["尚未出售之外幣，因匯率調整而發生之帳面盈益", "尚未出售之長期投資股票，因市價下跌而產生之帳面損失", "因員工退休而給付一筆退休金，該筆退休金完全從過去年度所提撥之退休金準備中支付", "銷貨收入中屬於附贈獎勵積點的部分，客戶尚未兌換該積點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00424', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '未婚之甲110年度之所得為股利100萬元及薪資所得120萬元，其申報扶養之父母各有股利6萬元 及4萬元，該申報戶邊際稅率為20%，有關甲110年度綜合所得稅結算申報，下列敘述何者正確？', '["該申報戶之股利，父母可各自選擇合併計稅減除股利可抵減稅額或單一稅率分開計稅", "該申報戶之股利全數適用單一稅率分開計稅，較為有利", "該申報戶之股利全數適用合併計稅減除股利可抵減稅額，較為有利", "該申報戶之全部股利，可抵減之稅額為股利合計數之8.5%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00425', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '外國A公司在中華民國境內設有分公司，A公司轉投資國內上市公司而獲配之股利所得，該筆股 利所得課稅方式為何？', '["依規定扣繳稅款，不計入營利事業所得額", "由A公司境內分公司計入免稅所得", "由A公司境內分公司計入營利事業所得額申報納稅", "該股利非屬中華民國來源所得，無須課稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00426', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '乙公司 110 年度全年度所得額為 500 萬元，其中包括停徵所得稅之有價證券交易所得額 250 萬 元，及出售土地免稅所得50萬元，其依所得基本稅額條例計算之基本稅額為何？', '["54萬元", "48萬元", "30萬元", "24萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00427', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '公司未依規定期限辦理營利事業所得稅結算申報，依所得稅法相關規定，下列敘述何者正確？', '["公司接到稽徵機關填發之滯報通知書之日起 15 日內補辦結算申報，按核定應納稅額另徵 20% 怠報金", "公司接到稽徵機關填發之滯報通知書之日起 15 日內補辦結算申報，按核定應納稅額另徵 10% 滯報金", "公司接到稽徵機關填發之滯報通知書後仍未補辦申報，按同業利潤標準核定所得額，補稅並加 徵滯納金", "公司接到稽徵機關填發之滯報通知書後補辦結算申報，按補繳稅額加計利息，免予處罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00428', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，有關營業稅之課徵，下列敘述何者錯誤？', '["營業人因進貨退出或折讓而收回之營業稅額，得於發生進貨退出或折讓之次期進項稅額中扣減之", "加值型及非加值型營業稅法第 14 條所定之銷售額，為營業人銷售貨物或勞務所收取之全部代 價，包括營業人在貨物或勞務之價額外收取之一切費用。但本次銷售之營業稅額不在其內", "營業人自用乘人小汽車之進項稅額，不得扣抵銷項稅額", "典當業得依查定之銷售額計算之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00429', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，營業人銷售下列何種貨物或勞務，不適用免徵營業稅？', '["報社銷售之廣告及電視臺之廣告播映", "土地", "碾米加工", "依第四章第二節規定計算稅額之營業人，銷售其非經常買進、賣出而持有之固定資產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00430', 'cpa', 'cpa-moex-111-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法及相關規定，營業人是某觀光飯店，下列那一項進項稅額，不得扣 抵銷項稅額？', '["購買載運貨物用小貨車", "購置總經理專用五人座座車", "購買載運員工上、下班用大型客車", "購置至機場接送旅客之客貨兩用車"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "5c80d29458d1", "answer_pdf_sha1": "cceb704b8470", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
